record.field:
for task in record.env['project.task'].search([('sale_order_id.id', '=', record.sale_id.id)]):
    if task.is_fsm: 
        for move in record.move_ids_without_package:
            if move.product_id.is_storable and move.product_id.tracking == "serial" and move.lot_ids not in task.x_serials:
                task['x_serials'] += move.lot_ids

for line in record.order_line:
    if line.x_maintained_serials not in record.x_maintained_serials:
        record['x_maintained_serials'] += line.x_maintained_serials
